async function upsertCategory(slug: string, name: string, icon: string, color: string, parentId: string | null) {
  const existing = await prisma.category.findUnique({ where: { slug } });
  if (existing) {
    return prisma.category.update({
      where: { id: existing.id },
      data: { name, icon, color, parentId },
    });
  }
  return prisma.category.create({ data: { slug, name, icon, color, parentId } });
}

async function main() {
  let createdQ = 0;
  let skippedQ = 0;

  for (const sub of SUBCATEGORIES) {
    const parent = await upsertCategory(sub.parent.slug, sub.parent.name, sub.parent.icon, sub.parent.color, null);
    const cat = await upsertCategory(sub.slug, sub.name, sub.icon, sub.color, parent.id);
    console.log(`\n📂 ${sub.parent.name} → ${sub.name}`);

    for (const q of sub.questions) {
      const existing = await prisma.question.findFirst({
        where: { categoryId: cat.id, text: q.text },
      });
      if (existing) {
        skippedQ++;
        continue;
      }
      await prisma.question.create({
        data: {
          text: q.text,
          difficulty: q.difficulty,
          type: "MULTIPLE_CHOICE",
          categoryId: cat.id,
          answers: {
            create: q.answers.map((text, i) => ({
              text,
              isCorrect: i === 0, // la prima è sempre la corretta
              order: i,
            })),
          },
        },
      });
      createdQ++;
    }
    console.log(`   ✓ ${sub.questions.length} domande processate`);
  }

  const total = await prisma.question.count();
  console.log(`\n✅ Seed completato. Create: ${createdQ}, Saltate (già presenti): ${skippedQ}. Totale domande nel DB: ${total}`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
